import csv
import re
import sys
from datetime import datetime

def normalize_date(value):
    value = value.strip()
    formats = [
        "%m/%d/%Y",
        "%Y-%m-%d",
        "%d-%b-%Y",
        "%d-%B-%Y"
    ]
    for fmt in formats:
        try:
            dt = datetime.strptime(value, fmt)
            return dt.strftime("%Y-%m-%d")
        except ValueError:
            continue
    return value

def normalize_phone(value):
    digits = re.sub(r'\D', '', value.strip())
    if len(digits) == 10:
        return f"+1{digits}"
    elif len(digits) == 11 and digits[0] == '1':
        return f"+{digits}"
    return value

def normalize_currency(value):
    value = value.strip().replace('$', '').replace(',', '')
    try:
        return str(float(value))
    except ValueError:
        return value

def normalize_field(value):
    return value.strip()

def normalize_csv(input_path, output_path):
    changes = 0
    with open(input_path, 'r', newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        fieldnames = reader.fieldnames
        rows = []
        for row in reader:
            new_row = {}
            for field, value in row.items():
                original = value
                if field == 'Date':
                    value = normalize_date(value)
                elif field == 'Phone':
                    value = normalize_phone(value)
                elif field == 'Amount':
                    value = normalize_currency(value)
                else:
                    value = normalize_field(value)

                if value != original:
                    changes += 1
                new_row[field] = value
            rows.append(new_row)

    with open(output_path, 'w', newline='', encoding='utf-8') as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames)
        writer.writeheader()
        writer.writerows(rows)

    return changes

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python csv_normalizer.py <input_path> <output_path>")
        sys.exit(1)

    input_path = sys.argv[1]
    output_path = sys.argv[2]

    changes = normalize_csv(input_path, output_path)
    print(f"Normalized {output_path}. Total cells changed: {changes}")
